"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { Menu, X } from "lucide-react";
import { useAuth } from "@/context/AuthContext";

const baseLinks = [
  { name: "Home",     href: "/" },
  { name: "About Us", href: "/about" },
  { name: "Menu",     href: "/menu" },
  { name: "Insights", href: "/insights" },
  { name: "Contact",  href: "/contact" },
  { name: "Voice AI", href: "/voice" },
];

export default function Navbar() {
  const [mobileOpen, setMobileOpen] = useState(false);
  const { role, logout } = useAuth();

  const navLinks = role === "admin" ? [...baseLinks, { name: "Orders", href: "/orders" }] : baseLinks;

  return (
    <>
      {/* ── Main nav bar ── */}
      <motion.nav
        initial={{ y: -80 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.5, ease: "easeOut" }}
        className="nav-root"
        style={{ zIndex: "var(--z-nav)" }}
      >
        <div className="nav-inner">
          {/* Logo */}
          <Link href="/" className="nav-logo">
            <div className="nav-logo-circle">
              <span style={{ color: "var(--color-gold)", fontFamily: "'Cormorant Garamond', serif", fontSize: "20px", fontWeight: 600 }}>
                A
              </span>
            </div>
            <div>
              <span style={{ color: "var(--color-text)", fontFamily: "'Cormorant Garamond', serif", fontSize: "20px", letterSpacing: "0.08em" }}>
                Aurora
              </span>
              <span style={{ display: "block", color: "rgba(201, 169, 110, 0.7)", fontSize: "9px", letterSpacing: "0.3em", textTransform: "uppercase", marginTop: "-2px" }}>
                Dining
              </span>
            </div>
          </Link>

          {/* Desktop nav links */}
          <nav className="nav-links nav-reserve-desktop" style={{ display: "flex", alignItems: "center", gap: "32px" }}>
            {navLinks.map((link) => (
              <Link key={link.name} href={link.href} className="nav-link animated-underline">
                {link.name}
              </Link>
            ))}
            {role === "admin" && (
              <span style={{ fontSize: "11px", letterSpacing: "0.15em", textTransform: "uppercase", color: "rgba(232,224,208,0.6)" }}>
                Admin
              </span>
            )}
            {role ? (
              <button
                onClick={logout}
                className="nav-reserve"
                style={{ background: "transparent" }}
              >
                Logout
              </button>
            ) : (
              <Link href="/login" className="nav-reserve">
                Login
              </Link>
            )}
          </nav>

          {/* Mobile hamburger */}
          <button
            onClick={() => setMobileOpen(!mobileOpen)}
            aria-label="Toggle menu"
            style={{
              display: "none",
              background: "transparent",
              border: "none",
              color: "var(--color-text)",
              cursor: "pointer",
              padding: "8px",
              transition: "color 0.2s",
            }}
            className="mobile-menu-btn"
          >
            {mobileOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>

        {/* Inline style to show hamburger on tablet/mobile */}
        <style>{`
          @media (max-width: 1024px) {
            .nav-links.nav-reserve-desktop { display: none !important; }
            .mobile-menu-btn { display: flex !important; }
          }
        `}</style>
      </motion.nav>

      {/* ── Mobile full-screen menu ── */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, y: -16 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -16 }}
            transition={{ duration: 0.25 }}
            style={{
              position: "fixed",
              inset: 0,
              top: "80px",
              zIndex: 99,
              backgroundColor: "rgba(10, 10, 10, 0.98)",
              backdropFilter: "blur(24px)",
              padding: "32px 24px",
              display: "flex",
              flexDirection: "column",
              gap: "8px",
              overflowY: "auto",
              overscrollBehavior: "contain",
            }}
          >
            {navLinks.map((link, i) => (
              <motion.div
                key={link.name}
                initial={{ opacity: 0, x: -24 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.06 }}
              >
                <Link
                  href={link.href}
                  onClick={() => setMobileOpen(false)}
                  style={{
                    display: "block",
                    padding: "16px 0",
                    fontFamily: "'Cormorant Garamond', serif",
                    fontSize: "28px",
                    fontWeight: 300,
                    color: "var(--color-text)",
                    textDecoration: "none",
                    borderBottom: "1px solid var(--color-border)",
                    transition: "color 0.2s",
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.color = "var(--color-gold)")}
                  onMouseLeave={(e) => (e.currentTarget.style.color = "var(--color-text)")}
                >
                  {link.name}
                </Link>
              </motion.div>
            ))}

            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.45 }}
              style={{ marginTop: "32px", display: "flex", justifyContent: "space-between", alignItems: "center", gap: "16px" }}
            >
              {role === "admin" && (
                <span style={{ fontSize: "11px", letterSpacing: "0.15em", textTransform: "uppercase", color: "rgba(232,224,208,0.65)" }}>
                  Admin
                </span>
              )}
              {role ? (
                <button
                  onClick={() => {
                    logout();
                    setMobileOpen(false);
                  }}
                  className="nav-reserve"
                  style={{ display: "inline-block", background: "transparent" }}
                >
                  Logout
                </button>
              ) : (
                <Link
                  href="/login"
                  onClick={() => setMobileOpen(false)}
                  className="nav-reserve"
                  style={{ display: "inline-block" }}
                >
                  Login
                </Link>
              )}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}
